//! Procedural gnosis-scene generator -> ffmpeg H.264 encode (the original frffmpeg).
//!
//! Frames render in parallel via gnosis-frf par-iter (fork/race/fold), then pipe RGB24 into
//! ffmpeg. Kept verbatim in behaviour; only lifted out of `main` into a callable.

use gnosis_frf::prelude::*;
use std::f32::consts::PI;
use std::io::Write;
use std::path::Path;
use std::process::{Command, Stdio};

const WIDTH: usize = 160;
const HEIGHT: usize = 90;
const OUTPUT_WIDTH: usize = 3840;
const OUTPUT_HEIGHT: usize = 2160;
const TOTAL_FRAMES: usize = 1440; // 12s loop

#[derive(Clone, Copy)]
struct Color {
    r: u8,
    g: u8,
    b: u8,
}

const CYAN: Color = Color { r: 0, g: 255, b: 255 };
const MAGENTA: Color = Color { r: 255, g: 0, b: 255 };
const GOLD: Color = Color { r: 255, g: 215, b: 0 };
const TEAL: Color = Color { r: 0, g: 128, b: 128 };
const DIM_WHITE: Color = Color { r: 60, g: 60, b: 60 };
const PINK: Color = Color { r: 255, g: 100, b: 200 };

fn set_pixel(rgba: &mut [u8], x: f32, y: f32, color: Color, alpha: f32) {
    let ix = x.floor() as isize;
    let iy = y.floor() as isize;
    if ix < 0 || iy < 0 || ix >= WIDTH as isize || iy >= HEIGHT as isize {
        return;
    }
    let idx = ((iy as usize) * WIDTH + (ix as usize)) * 4;
    let inv_alpha = 1.0 - alpha;
    rgba[idx] = (rgba[idx] as f32 * inv_alpha + color.r as f32 * alpha).round() as u8;
    rgba[idx + 1] = (rgba[idx + 1] as f32 * inv_alpha + color.g as f32 * alpha).round() as u8;
    rgba[idx + 2] = (rgba[idx + 2] as f32 * inv_alpha + color.b as f32 * alpha).round() as u8;
    rgba[idx + 3] = 255;
}

fn scene_gnosis_clockwork(rgba: &mut [u8], seq: usize, breath: f32, seed: f32) {
    let cx = WIDTH as f32 / 2.0;
    let cy = HEIGHT as f32 / 2.0;
    let t1 = seq as f32 * 0.01 + seed;
    let t3 = seq as f32 * 0.03 + seed * 0.5;
    let t4 = seq as f32 * 0.04 + seed * 0.7;
    for i in 0..12 {
        let a = (i as f32 / 12.0) * PI * 2.0 + t1;
        let r = 40.0 * breath;
        set_pixel(rgba, cx + a.cos() * r, cy + a.sin() * r, GOLD, 0.8);
    }
    for i in 0..4 {
        let a = (i as f32 / 4.0) * PI * 2.0 - t4;
        let r = 25.0 * breath;
        set_pixel(rgba, cx + a.cos() * r, cy + a.sin() * r, CYAN, 0.9);
    }
    for i in 0..3 {
        let a = (i as f32 / 3.0) * PI * 2.0 + t3;
        let r = 10.0 * breath;
        set_pixel(rgba, cx + a.cos() * r, cy + a.sin() * r, MAGENTA, 1.0);
    }
}

fn scene_closure_tower(rgba: &mut [u8], seq: usize, breath: f32, seed: f32) {
    let cx = WIDTH as f32 / 2.0;
    let cy = HEIGHT as f32 / 2.0;
    let phase = (seq % 360) as f32 / 360.0 + seed;
    for y in 0..HEIGHT {
        for x in 0..WIDTH {
            for l in -1..5 {
                let scale = 3.0f32.powf(l as f32 + (phase % 1.0)) * breath * 1.5;
                let dist = ((x as f32 - cx).abs()).max((y as f32 - cy).abs());
                if (dist - scale).abs() < 0.5 {
                    let alpha = 1.0 - (l as f32 + (phase % 1.0) - 2.0).abs() / 3.0;
                    let color = if l % 3 == 0 {
                        CYAN
                    } else if l % 3 == 1 {
                        MAGENTA
                    } else {
                        GOLD
                    };
                    set_pixel(rgba, x as f32, y as f32, color, alpha.max(0.0));
                }
            }
        }
    }
}

fn scene_braided_infinity(rgba: &mut [u8], seq: usize, breath: f32, seed: f32) {
    let t = seq as f32 * 0.05 + seed;
    for y in 0..HEIGHT {
        for x in 0..WIDTH {
            let tx = x % 40;
            let ty = y % 20;
            let x1 = 20.0 + (ty as f32 * 0.3 + t).sin() * 15.0 * breath;
            let x2 = 20.0 + (ty as f32 * 0.3 + t + PI).sin() * 15.0 * breath;
            if (tx as f32 - x1).abs() < 1.0 {
                set_pixel(rgba, x as f32, y as f32, MAGENTA, 0.9);
            } else if (tx as f32 - x2).abs() < 1.0 {
                set_pixel(rgba, x as f32, y as f32, CYAN, 0.9);
            }
        }
    }
}

fn scene_amplituhedron(rgba: &mut [u8], seq: usize, breath: f32, seed: f32) {
    let t = seq as f32 * 0.02 + seed;
    for y in 0..HEIGHT {
        for x in 0..WIDTH {
            let dx = x as f32 - WIDTH as f32 / 2.0;
            let dy = y as f32 - HEIGHT as f32 / 2.0;
            let d = (dx * dx + (dy * 2.0) * (dy * 2.0)).sqrt();
            let wave = (d * 0.2 * breath - t).sin() + (x as f32 * 0.1 + t).cos();
            if wave > 1.2 {
                set_pixel(rgba, x as f32, y as f32, GOLD, 0.9);
            } else if wave > 0.5 {
                set_pixel(rgba, x as f32, y as f32, TEAL, 0.6);
            }
        }
    }
}

fn scene_topological_convergence(rgba: &mut [u8], seq: usize, breath: f32, seed: f32) {
    let cx = WIDTH as f32 / 2.0;
    let cy = HEIGHT as f32 / 2.0;
    let t = seq as f32 * 0.01 + seed;
    let constants = [1, 3, 4, 12];
    for &c in &constants {
        let radius = c as f32 * 4.0 * breath;
        for i in 0..48 {
            let a = (i as f32 / 48.0) * PI * 2.0 + (t * (12.0 / c as f32));
            set_pixel(
                rgba,
                cx + a.cos() * radius,
                cy + a.sin() * radius,
                if c == 12 { GOLD } else { DIM_WHITE },
                0.8,
            );
        }
    }
}

fn scene_pisot_mitosis(rgba: &mut [u8], seq: usize, breath: f32, seed: f32) {
    let t = seq as f32 * 0.05 + seed;
    for y in 0..HEIGHT {
        for x in 0..WIDTH {
            let val = (x as f32 * 0.08 + t).sin() * (y as f32 * 0.08 + t * breath).sin();
            if val > 0.8 {
                set_pixel(rgba, x as f32, y as f32, GOLD, 0.9);
            } else if val < -0.8 {
                set_pixel(rgba, x as f32, y as f32, PINK, 0.9);
            }
        }
    }
}

fn render_frame(seq: usize, scene_idx: usize, breath: f32, seed: f32) -> Vec<u8> {
    let mut rgba = vec![0u8; WIDTH * HEIGHT * 4];
    match scene_idx % 6 {
        0 => scene_gnosis_clockwork(&mut rgba, seq, breath, seed),
        1 => scene_closure_tower(&mut rgba, seq, breath, seed),
        2 => scene_braided_infinity(&mut rgba, seq, breath, seed),
        3 => scene_amplituhedron(&mut rgba, seq, breath, seed),
        4 => scene_topological_convergence(&mut rgba, seq, breath, seed),
        5 => scene_pisot_mitosis(&mut rgba, seq, breath, seed),
        _ => unreachable!(),
    }
    let mut rgb = vec![0u8; WIDTH * HEIGHT * 3];
    for j in 0..(WIDTH * HEIGHT) {
        rgb[j * 3] = rgba[j * 4];
        rgb[j * 3 + 1] = rgba[j * 4 + 1];
        rgb[j * 3 + 2] = rgba[j * 4 + 2];
    }
    rgb
}

/// Render `scene_idx` to `out_path` as H.264, parallelising frame render via gnosis-frf.
/// No-op if `out_path` already exists (idempotent, as the original).
pub fn generate_video(scene_idx: usize, out_path: &str, seed: f32) {
    if Path::new(out_path).exists() {
        return;
    }

    let mut child = Command::new("ffmpeg")
        .args([
            "-f",
            "rawvideo",
            "-pixel_format",
            "rgb24",
            "-video_size",
            &format!("{OUTPUT_WIDTH}x{OUTPUT_HEIGHT}"),
            "-framerate",
            "120",
            "-i",
            "pipe:0",
            "-c:v",
            "libx264",
            "-preset",
            "ultrafast",
            "-crf",
            "18",
            "-pix_fmt",
            "yuv420p",
            "-y",
            out_path,
        ])
        .stdin(Stdio::piped())
        .stdout(Stdio::null())
        .stderr(Stdio::null())
        .spawn()
        .unwrap();

    let mut stdin = child.stdin.take().unwrap();
    const BATCH_SIZE: usize = 64;
    for b in (0..TOTAL_FRAMES).step_by(BATCH_SIZE) {
        let end = (b + BATCH_SIZE).min(TOTAL_FRAMES);
        let batch_frames: Vec<Vec<u8>> = (b..end)
            .into_par_iter()
            .map(|i| {
                let rgb = render_frame(i, scene_idx, 1.0, seed);
                let mut scaled = vec![0u8; OUTPUT_WIDTH * OUTPUT_HEIGHT * 3];
                let scale_x = OUTPUT_WIDTH / WIDTH;
                let scale_y = OUTPUT_HEIGHT / HEIGHT;
                for y in 0..OUTPUT_HEIGHT {
                    let src_y = y / scale_y;
                    let src_row = src_y * WIDTH;
                    let dst_row = y * OUTPUT_WIDTH;
                    for x in 0..OUTPUT_WIDTH {
                        let src_x = x / scale_x;
                        let src_idx = (src_row + src_x) * 3;
                        let dst_idx = (dst_row + x) * 3;
                        scaled[dst_idx] = rgb[src_idx];
                        scaled[dst_idx + 1] = rgb[src_idx + 1];
                        scaled[dst_idx + 2] = rgb[src_idx + 2];
                    }
                }
                scaled
            })
            .with_sub_chunks_auto()
            .collect();
        for frame in batch_frames {
            stdin.write_all(&frame).unwrap();
        }
    }
    drop(stdin);
    child.wait().unwrap();
}
